    cdef float mrr = 0.0
    cdef float rr = 0.0
    cdef float our_guess = 0.0
    cdef int[:] lgr
    cdef int[:] pgr

    for gr in range(n_groups):
        idx_one = 0
        ggr = g[gr]
        for i in range(ggr):
            if l[index+i]==1:
                idx_one = i+index
        our_guess = p[idx_one]
        times_worse = 0
        for i in range(ggr):
            if p[index+i] >= our_guess:
                times_worse += 1
        rr = 1.0/times_worse
        time = gr+1.0
        mrr = ((time-1)/(time))*mrr + (1/time)*rr
        index += ggr

    return mrr

def instrs(inp):
    instructions = []
    for instruction in inp.strip().split(","):
        if instruction[0] == "s":
            d = int(instruction[1:])
            instructions.append(("s", d))
        elif instruction[0] == "x":
            a, b = map(int, instruction[1:].split('/'))
            instructions.append(("x", a, b))
        else:
            n1, n2 = map(lambda x: ord(x) - 97, instruction[1:].split('/'))
            instructions.append(("s", n1, n2))
    return instructions

